svg.script:
(function () {
  var svg = document.currentScript && document.currentScript.ownerSVGElement;
  if (!svg) return;

  function decodeEntities(value) {
    var textarea = document.createElement('textarea');
    textarea.innerHTML = String(value || '');
    return textarea.value;
  }

  function shortName(value) {
    return decodeEntities(value).trim().replace(/\s+/g, ' ');
  }

  function featuredData() {
    var guide = svg.closest('[data-kcsg-guide]');
    if (!guide) return [];
    var dataNode = guide.querySelector('[data-kcsg-data]');
    if (!dataNode) return [];
    try {
      var data = JSON.parse(dataNode.textContent || '{}');
      return Array.isArray(data.featuredLocations) ? data.featuredLocations : [];
    } catch (error) {
      return [];
    }
  }

  function stopPoint(stopId) {
    var stop = svg.querySelector('#stops > g#' + CSS.escape(stopId));
    if (!stop) return null;
    var circle = stop.querySelector('circle');
    if (!circle) return null;
    return {
      stop: stop,
      x: parseFloat(circle.getAttribute('cx') || '0'),
      y: parseFloat(circle.getAttribute('cy') || '0')
    };
  }

  function addText(parent, className, x, y, text) {
    var node = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    node.setAttribute('class', className);
    node.setAttribute('x', String(x));
    node.setAttribute('y', String(y));
    node.textContent = text;
    parent.appendChild(node);
    return node;
  }

  function render() {
    var layer = svg.querySelector('#kcsg-featured-map-locations');
    if (!layer) return;
    while (layer.firstChild) layer.removeChild(layer.firstChild);

    var byStop = {};
    featuredData().forEach(function (location) {
      if (!location || !location.enabled || !location.name || !location.stop) return;
      if (!byStop[location.stop]) byStop[location.stop] = [];
      byStop[location.stop].push(location);
    });

    Object.keys(byStop).forEach(function (stopId) {
      var point = stopPoint(stopId);
      if (!point) return;

      byStop[stopId].slice(0, 4).forEach(function (location, index) {
        var y = point.y + 23 + (index * 15.8);
        var x = point.x + 13;
        var item = document.createElementNS('http://www.w3.org/2000/svg', 'g');
        item.setAttribute('class', 'kcsg-map-feature-item');
        item.setAttribute('role', 'button');
        item.setAttribute('tabindex', '0');
        item.setAttribute('aria-label', 'Show ' + shortName(location.name) + ' near ' + stopId.replace(/^stop-/, '').replace(/-/g, ' '));

        addText(item, 'kcsg-map-feature-star', x, y, '★');
        addText(item, 'kcsg-map-feature-label', x + 12, y - 2, shortName(location.name));

        function activate() {
          if (point.stop && typeof point.stop.dispatchEvent === 'function') {
            point.stop.dispatchEvent(new MouseEvent('click', { bubbles: true }));
          }
        }

        item.addEventListener('click', activate);
        item.addEventListener('keydown', function (event) {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            activate();
          }
        });

        layer.appendChild(item);
      });
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', render);
  } else {
    window.requestAnimationFrame(render);
  }
})();
